44	const componentGroupPremium = (count: number): number =>
45	  count === COMPONENT_BLOCK_SIZE
46	    ? COMPONENT_BLOCK_PREMIUM
47	    : count * COMPONENT_BASE_PREMIUM;
48	
49	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
50	
51	const isHighEnchantment = (item: Item): boolean =>
52	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
53	
54	const qualifiesForFirstInsurance = (item: Item, isSingleItemPolicy: boolean): boolean =>
55	  isSingleItemPolicy && !!item.cursed && !isHighEnchantment(item);
56	
57	const surchargeRates = (item: Item, isSingleItemPolicy: boolean): number[] => [
58	  item.cursed ? CURSE_SURCHARGE_RATE : 0,
59	  isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0,
60	  qualifiesForFirstInsurance(item, isSingleItemPolicy) ? FIRST_INSURANCE_RATE : 0,
61	];
62	
63	const mainItemPremium = (item: Item, isSingleItemPolicy: boolean): number => {
64	  const base = BASE_PREMIUM_BY_TYPE[item.type];
65	  const totalRate = surchargeRates(item, isSingleItemPolicy).reduce((a, b) => a + b, 1);
66	  return base * totalRate;
67	};
68	
69	const countByType = (items: Item[]): Map<string, number> =>
70	  items.reduce(
71	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
72	    new Map<string, number>(),
73	  );
74	
75	const sumComponentPremiums = (components: Item[]): number =>
76	  [...countByType(components).values()]
77	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
78	
79	const partitionItems = (items: Item[]): { mains: Item[]; components: Item[] } =>
80	  items.reduce<{ mains: Item[]; components: Item[] }>(
81	    (acc, item) => {
82	      (isMainItem(item) ? acc.mains : acc.components).push(item);
83	      return acc;
84	    },
85	    { mains: [], components: [] },
86	  );
