88	const sumItemPremiums = (items: Item[], policyRate: number): number => {
89	  const { mains, components } = partitionItems(items);
90	  const isSingleItemPolicy = items.length === 1;
91	  const mainsBaseSum = mains.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
92	  const mainsPremiumSum = mains.reduce((sum, item) => sum + mainItemPremium(item, isSingleItemPolicy), 0);
93	  const componentsSum = sumComponentPremiums(components);
94	  return mainsPremiumSum + componentsSum + (mainsBaseSum + componentsSum) * policyRate;
95	};
