97	const customerRateAdjustments = (customer: Customer, isFollowUp: boolean): number[] => [
98	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -LOYALTY_DISCOUNT_RATE : 0,
99	  customer.firstQuote ? FIRST_INSURANCE_RATE : 0,
100	  isFollowUp ? -FOLLOWUP_DISCOUNT_RATE : 0,
101	];
102	
103	const policyWideRate = (customer: Customer, isFollowUp: boolean): number =>
104	  customerRateAdjustments(customer, isFollowUp).reduce((sum, rate) => sum + rate, 0);
105	
106	const ceilInFavor = (value: number): number => Math.ceil(Number(value.toFixed(6)));
107	
108	const quotePremiumFor = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => ({
109	  premium: ceilInFavor(sumItemPremiums(step.items, policyWideRate(customer, isFollowUp)) + PROCESSING_FEE),
110	});
111	
112	const itemInsuranceValue = (item: Item): number =>
113	  isMainItem(item) ? INSURANCE_VALUE_BY_TYPE[item.type] : COMPONENT_INSURANCE_VALUE;
114	
115	const policyInsuranceSum = (items: Item[]): number =>
116	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
117	
118	const damagePayout = (damage: Damage): number =>
119	  Math.max(0, damage.amount - DEDUCTIBLE);
120	
121	const claimResult = (step: ClaimStep, policyItems: Item[]): { payout: number; remainingCap: number } => {
122	  const insuranceSum = policyInsuranceSum(policyItems);
123	  const cap = insuranceSum * CAP_MULTIPLIER;
124	  const payout = step.incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
125	  return { payout, remainingCap: cap - payout };
126	};
