132	      results.push(quotePremiumFor(step, scenario.customer, i > 0));
133	    } else {
134	      const policyStep = scenario.steps[step.policy] as QuoteStep;
135	      results.push(claimResult(step, policyStep.items));
136	    }
137	  });
138	  return { results };
139	};
